{"content":"1: package scanner
2: 
3: import (
4: 	"context"
5: 	"io/fs"
6: 	"os"
7: 	"path/filepath"
8: 	"slices"
9: 	"sort"
10: 	"strings"
11: 	"time"
12: 
13: 	"github.com/navidrome/navidrome/conf"
14: 	"github.com/navidrome/navidrome/core"
15: 	"github.com/navidrome/navidrome/core/artwork"
16: 	"github.com/navidrome/navidrome/core/auth"
17: 	"github.com/navidrome/navidrome/log"
18: 	"github.com/navidrome/navidrome/model"
19: 	"github.com/navidrome/navidrome/model/request"
20: 	"github.com/navidrome/navidrome/scanner/metadata"
21: 	_ "github.com/navidrome/navidrome/scanner/metadata/ffmpeg"
22: 	_ "github.com/navidrome/navidrome/scanner/metadata/taglib"
23: 	"github.com/navidrome/navidrome/utils/pl"
24: 	"golang.org/x/sync/errgroup"
25: )
26: 
27: type TagScanner struct {
28: 	// Dependencies
29: 	ds          model.DataStore
30: 	playlists   core.Playlists
31: 	cacheWarmer artwork.CacheWarmer
32: 
33: 	// Internal state
34: 	lib    model.Library
35: 	cnt    *counters
36: 	mapper *MediaFileMapper
37: }
38: 
39: func NewTagScanner(ds model.DataStore, playlists core.Playlists, cacheWarmer artwork.CacheWarmer) FolderScanner {
40: 	s := &TagScanner{
41: 		ds:          ds,
42: 		cacheWarmer: cacheWarmer,
43: 		playlists:   playlists,
44: 	}
45: 	metadata.LogExtractors()
46: 
47: 	return s
48: }
49: 
50: type dirMap map[string]dirStats
51: 
52: type counters struct {
53: 	added     int64
54: 	updated   int64
55: 	deleted   int64
56: 	playlists int64
57: }
58: 
59: func (cnt *counters) total() int64 { return cnt.added + cnt.updated + cnt.deleted }
60: 
61: const (
62: 	// filesBatchSize used for batching file metadata extraction
63: 	filesBatchSize = 100
64: )
65: 
66: // Scan algorithm overview:
67: // Load all directories from the DB
68: // Traverse the music folder, collecting each subfolder's ModTime (self or any non-dir children, whichever is newer)
69: // For each changed folder: get all files from DB whose path starts with the changed folder (non-recursively), check each file:
70: // - if file in folder is newer, update the one in DB
71: // - if file in folder does not exists in DB, add it
72: // - for each file in the DB that is not found in the folder, delete it from DB
73: // Compare directories in the fs with the ones in the DB to find deleted folders
74: // For each deleted folder: delete all files from DB whose path starts with the delete folder path (non-recursively)
75: // Create new albums/artists, update counters:
76: // - collect all albumIDs and artistIDs from previous steps
77: // - refresh the collected albums and artists with the metadata from the mediafiles
78: // For each changed folder, process playlists:
79: // - If the playlist is not in the DB, import it, setting sync = true
80: // - If the playlist is in the DB and sync == true, import it, or else skip it
81: // Delete all empty albums, delete all empty artists, clean-up playlists
82: func (s *TagScanner) Scan(ctx context.Context, lib model.Library, fullScan bool, progress chan uint32) (int64, error) {
83: 	ctx = auth.WithAdminUser(ctx, s.ds)
84: 	start := time.Now()
85: 
86: 	// Update internal copy of Library
87: 	s.lib = lib
88: 
89: 	// Special case: if LastScanAt is zero, re-import all files
90: 	fullScan = fullScan || s.lib.LastScanAt.IsZero()
91: 
92: 	// If the media folder is empty (no music and no subfolders), abort to avoid deleting all data from DB
93: 	empty, err := isDirEmpty(ctx, s.lib.Path)
94: 	if err != nil {
95: 		return 0, err
96: 	}
97: 	if empty && !fullScan {
98: 		log.Error(ctx, "Media Folder is empty. Aborting scan.", "folder", s.lib.Path)
99: 		return 0, nil
100: 	}
101: 
102: 	allDBDirs, err := s.getDBDirTree(ctx)
103: 	if err != nil {
104: 		return 0, err
105: 	}
106: 
107: 	allFSDirs := dirMap{}
108: 	var changedDirs []string
109: 	s.cnt = &counters{}
110: 	genres := newCachedGenreRepository(ctx, s.ds.Genre(ctx))
111: 	s.mapper = NewMediaFileMapper(s.lib.Path, genres)
112: 	refresher := newRefresher(s.ds, s.cacheWarmer, s.lib, allFSDirs)
113: 
114: 	log.Trace(ctx, "Loading directory tree from music folder", "folder", s.lib.Path)
115: 	foldersFound, walkerError := walkDirTree(ctx, s.lib.Path)
116: 
117: 	// Process each folder found in the music folder
118: 	g, walkCtx := errgroup.WithContext(ctx)
119: 	g.Go(func() error {
120: 		for folderStats := range pl.ReadOrDone(walkCtx, foldersFound) {
121: 			updateProgress(progress, folderStats.AudioFilesCount)
122: 			allFSDirs[folderStats.Path] = folderStats
123: 
124: 			if s.folderHasChanged(folderStats, allDBDirs, s.lib.LastScanAt) || fullScan {
125: 				changedDirs = append(changedDirs, folderStats.Path)
126: 				log.Debug("Processing changed folder", "dir", folderStats.Path)
127: 				err := s.processChangedDir(walkCtx, refresher, fullScan, folderStats.Path)
128: 				if err != nil {
129: 					log.Error("Error updating folder in the DB", "dir", folderStats.Path, err)
130: 				}
131: 			}
132: 		}
133: 		return nil
134: 	})
135: 	// Check for errors in the walker
136: 	g.Go(func() error {
137: 		for err := range walkerError {
138: 			log.Error("Scan was interrupted by error. See errors above", err)
139: 			return err
140: 		}
141: 		return nil
142: 	})
143: 	// Wait for all goroutines to finish, and check if an error occurred
144: 	if err := g.Wait(); err != nil {
145: 		return 0, err
146: 	}
147: 
148: 	deletedDirs := s.getDeletedDirs(ctx, allFSDirs, allDBDirs)
149: 	if len(deletedDirs)+len(changedDirs) == 0 {
150: 		log.Debug(ctx, "No changes found in Music Folder", "folder", s.lib.Path, "elapsed", time.Since(start))
151: 		return 0, nil
152: 	}
153: 
154: 	for _, dir := range deletedDirs {
155: 		err := s.processDeletedDir(ctx, refresher, dir)
156: 		if err != nil {
157: 			log.Error("Error removing deleted folder from DB", "dir", dir, err)
158: 		}
159: 	}
160: 
161: 	s.cnt.playlists = 0
162: 	if conf.Server.AutoImportPlaylists {
163: 		// Now that all mediafiles are imported/updated, search for and import/update playlists
164: 		u, _ := request.UserFrom(ctx)
165: 		for _, dir := range changedDirs {
166: 			info := allFSDirs[dir]
167: 			if info.HasPlaylist {
168: 				if !u.IsAdmin {
169: 					log.Warn("Playlists will not be imported, as there are no admin users yet, "+
170: 						"Please create an admin user first, and then update the playlists for them to be imported", "dir", dir)
171: 				} else {
172: 					plsSync := newPlaylistImporter(s.ds, s.playlists, s.cacheWarmer, lib.Path)
173: 					s.cnt.playlists = plsSync.processPlaylists(ctx, dir)
174: 				}
175: 			}
176: 		}
177: 	} else {
178: 		log.Debug("Playlist auto-import is disabled")
179: 	}
180: 
181: 	err = s.ds.GC(log.NewContext(ctx), s.lib.Path)
182: 	log.Info("Finished processing Music Folder", "folder", s.lib.Path, "elapsed", time.Since(start),
183: 		"added", s.cnt.added, "updated", s.cnt.updated, "deleted", s.cnt.deleted, "playlistsImported", s.cnt.playlists)
184: 
185: 	return s.cnt.total(), err
186: }
187: 
188: func updateProgress(progress chan uint32, count uint32) {
189: 	select {
190: 	case progress <- count:
191: 	default: // It is ok to miss a count update
192: 	}
193: }
194: 
195: func isDirEmpty(ctx context.Context, dir string) (bool, error) {
196: 	children, stats, err := loadDir(ctx, dir)
197: 	if err != nil {
198: 		return false, err
199: 	}
200: 	return len(children) == 0 && stats.AudioFilesCount == 0, nil
201: }
202: 
203: func (s *TagScanner) getDBDirTree(ctx context.Context) (map[string]struct{}, error) {
204: 	start := time.Now()
205: 	log.Trace(ctx, "Loading directory tree from database", "folder", s.lib.Path)
206: 
207: 	repo := s.ds.MediaFile(ctx)
208: 	dirs, err := repo.FindPathsRecursively(s.lib.Path)
209: 	if err != nil {
210: 		return nil, err
211: 	}
212: 	resp := map[string]struct{}{}
213: 	for _, d := range dirs {
214: 		resp[filepath.Clean(d)] = struct{}{}
215: 	}
216: 
217: 	log.Debug("Directory tree loaded from DB", "total", len(resp), "elapsed", time.Since(start))
218: 	return resp, nil
219: }
220: 
221: func (s *TagScanner) folderHasChanged(folder dirStats, dbDirs map[string]struct{}, lastModified time.Time) bool {
222: 	_, inDB := dbDirs[folder.Path]
223: 	// If is a new folder with at least one song OR it was modified after lastModified
224: 	return (!inDB && (folder.AudioFilesCount > 0)) || folder.ModTime.After(lastModified)
225: }
226: 
227: func (s *TagScanner) getDeletedDirs(ctx context.Context, fsDirs dirMap, dbDirs map[string]struct{}) []string {
228: 	start := time.Now()
229: 	log.Trace(ctx, "Checking for deleted folders")
230: 	var deleted []string
231: 
232: 	for d := range dbDirs {
233: 		if _, ok := fsDirs[d]; !ok {
234: 			deleted = append(deleted, d)
235: 		}
236: 	}
237: 
238: 	sort.Strings(deleted)
239: 	log.Debug(ctx, "Finished deleted folders check", "total", len(deleted), "elapsed", time.Since(start))
240: 	return deleted
241: }
242: 
243: func (s *TagScanner) processDeletedDir(ctx context.Context, refresher *refresher, dir string) error {
244: 	start := time.Now()
245: 
246: 	mfs, err := s.ds.MediaFile(ctx).FindAllByPath(dir)
247: 	if err != nil {
248: 		return err
249: 	}
250: 
251: 	c, err := s.ds.MediaFile(ctx).DeleteByPath(dir)
252: 	if err != nil {
253: 		return err
254: 	}
255: 	s.cnt.deleted += c
256: 
257: 	for _, t := range mfs {
258: 		refresher.accumulate(t)
259: 	}
260: 
261: 	err = refresher.flush(ctx)
262: 	log.Info(ctx, "Finished processing deleted folder", "dir", dir, "purged", len(mfs), "elapsed", time.Since(start))
263: 	return err
264: }
265: 
266: func (s *TagScanner) processChangedDir(ctx context.Context, refresher *refresher, fullScan bool, dir string) error {
267: 	start := time.Now()
268: 
269: 	// Load folder's current tracks from DB into a map
270: 	currentTracks := map[string]model.MediaFile{}
271: 	ct, err := s.ds.MediaFile(ctx).FindAllByPath(dir)
272: 	if err != nil {
273: 		return err
274: 	}
275: 	for _, t := range ct {
276: 		currentTracks[t.Path] = t
277: 	}
278: 
279: 	// Load track list from the folder
280: 	files, err := loadAllAudioFiles(dir)
281: 	if err != nil {
282: 		return err
283: 	}
284: 
285: 	// If no files to process, return
286: 	if len(files)+len(currentTracks) == 0 {
287: 		return nil
288: 	}
289: 
290: 	orphanTracks := map[string]model.MediaFile{}
291: 	for k, v := range currentTracks {
292: 		orphanTracks[k] = v
293: 	}
294: 
295: 	// If track from folder is newer than the one in DB, select for update/insert in DB
296: 	log.Trace(ctx, "Processing changed folder", "dir", dir, "tracksInDB", len(currentTracks), "tracksInFolder", len(files))
297: 	var filesToUpdate []string
298: 	for filePath, entry := range files {
299: 		c, inDB := currentTracks[filePath]
300: 		if !inDB || fullScan {
301: 			filesToUpdate = append(filesToUpdate, filePath)
302: 			s.cnt.added++
303: 		} else {
304: 			info, err := entry.Info()
305: 			if err != nil {
306: 				log.Error("Could not stat file", "filePath", filePath, err)
307: 				continue
308: 			}
309: 			if info.ModTime().After(c.UpdatedAt) {
310: 				filesToUpdate = append(filesToUpdate, filePath)
311: 				s.cnt.updated++
312: 			}
313: 		}
314: 
315: 		// Force a refresh of the album and artist, to cater for cover art files
316: 		refresher.accumulate(c)
317: 
318: 		// Only leaves in orphanTracks the ones not found in the folder. After this loop any remaining orphanTracks
319: 		// are considered gone from the music folder and will be deleted from DB
320: 		delete(orphanTracks, filePath)
321: 	}
322: 
323: 	numUpdatedTracks := 0
324: 	numPurgedTracks := 0
325: 
326: 	if len(filesToUpdate) > 0 {
327: 		numUpdatedTracks, err = s.addOrUpdateTracksInDB(ctx, refresher, dir, currentTracks, filesToUpdate)
328: 		if err != nil {
329: 			return err
330: 		}
331: 	}
332: 
333: 	if len(orphanTracks) > 0 {
334: 		numPurgedTracks, err = s.deleteOrphanSongs(ctx, refresher, dir, orphanTracks)
335: 		if err != nil {
336: 			return err
337: 		}
338: 	}
339: 
340: 	err = refresher.flush(ctx)
341: 	log.Info(ctx, "Finished processing changed folder", "dir", dir, "updated", numUpdatedTracks,
342: 		"deleted", numPurgedTracks, "elapsed", time.Since(start))
343: 	return err
344: }
345: 
346: func (s *TagScanner) deleteOrphanSongs(
347: 	ctx context.Context,
348: 	refresher *refresher,
349: 	dir string,
350: 	tracksToDelete map[string]model.MediaFile,
351: ) (int, error) {
352: 	numPurgedTracks := 0
353: 
354: 	log.Debug(ctx, "Deleting orphan tracks from DB", "dir", dir, "numTracks", len(tracksToDelete))
355: 	// Remaining tracks from DB that are not in the folder are deleted
356: 	for _, ct := range tracksToDelete {
357: 		numPurgedTracks++
358: 		refresher.accumulate(ct)
359: 		if err := s.ds.MediaFile(ctx).Delete(ct.ID); err != nil {
360: 			return 0, err
361: 		}
362: 		s.cnt.deleted++
363: 	}
364: 	return numPurgedTracks, nil
365: }
366: 
367: func (s *TagScanner) addOrUpdateTracksInDB(
368: 	ctx context.Context,
369: 	refresher *refresher,
370: 	dir string,
371: 	currentTracks map[string]model.MediaFile,
372: 	filesToUpdate []string,
373: ) (int, error) {
374: 	log.Trace(ctx, "Updating mediaFiles in DB", "dir", dir, "numFiles", len(filesToUpdate))
375: 
376: 	numUpdatedTracks := 0
377: 	// Break the file list in chunks to avoid calling ffmpeg with too many parameters
378: 	for chunk := range slices.Chunk(filesToUpdate, filesBatchSize) {
379: 		// Load tracks Metadata from the folder
380: 		newTracks, err := s.loadTracks(chunk)
381: 		if err != nil {
382: 			return 0, err
383: 		}
384: 
385: 		// If track from folder is newer than the one in DB, update/insert in DB
386: 		log.Trace(ctx, "Updating mediaFiles in DB", "dir", dir, "files", chunk, "numFiles", len(chunk))
387: 		for i := range newTracks {
388: 			n := newTracks[i]
389: 			// Keep current annotations if the track is in the DB
390: 			if t, ok := currentTracks[n.Path]; ok {
391: 				n.Annotations = t.Annotations
392: 			}
393: 			n.LibraryID = s.lib.ID
394: 			err := s.ds.MediaFile(ctx).Put(&n)
395: 			if err != nil {
396: 				return 0, err
397: 			}
398: 			refresher.accumulate(n)
399: 			numUpdatedTracks++
400: 		}
401: 	}
402: 	return numUpdatedTracks, nil
403: }
404: 
405: func (s *TagScanner) loadTracks(filePaths []string) (model.MediaFiles, error) {
406: 	mds, err := metadata.Extract(filePaths...)
407: 	if err != nil {
408: 		return nil, err
409: 	}
410: 
411: 	var mfs model.MediaFiles
412: 	for _, md := range mds {
413: 		mf := s.mapper.ToMediaFile(md)
414: 		mfs = append(mfs, mf)
415: 	}
416: 	return mfs, nil
417: }
418: 
419: func loadAllAudioFiles(dirPath string) (map[string]fs.DirEntry, error) {
420: 	files, err := fs.ReadDir(os.DirFS(dirPath), ".")
421: 	if err != nil {
422: 		return nil, err
423: 	}
424: 	fileInfos := make(map[string]fs.DirEntry)
425: 	for _, f := range files {
426: 		if f.IsDir() {
427: 			continue
428: 		}
429: 		if strings.HasPrefix(f.Name(), ".") {
430: 			continue
431: 		}
432: 		filePath := filepath.Join(dirPath, f.Name())
433: 		if !model.IsAudioFile(filePath) {
434: 			continue
435: 		}
436: 		fileInfos[filePath] = f
437: 	}
438: 
439: 	return fileInfos, nil
440: }
