19: // refresher is responsible for rolling up mediafiles attributes into albums attributes,
20: // and albums attributes into artists attributes. This is done by accumulating all album and artist IDs
21: // found during scan, and "refreshing" the albums and artists when flush is called.
22: //
23: // The actual mappings happen in MediaFiles.ToAlbum() and Albums.ToAlbumArtist()
24: type refresher struct {
25: 	ds          model.DataStore
26: 	lib         model.Library
27: 	album       map[string]struct{}
28: 	artist      map[string]struct{}
29: 	dirMap      dirMap
30: 	cacheWarmer artwork.CacheWarmer
31: }
32: 
33: func newRefresher(ds model.DataStore, cw artwork.CacheWarmer, lib model.Library, dirMap dirMap) *refresher {
34: 	return &refresher{
35: 		ds:          ds,
36: 		lib:         lib,
37: 		album:       map[string]struct{}{},
38: 		artist:      map[string]struct{}{},
39: 		dirMap:      dirMap,
40: 		cacheWarmer: cw,
41: 	}
42: }
43: 
44: func (r *refresher) accumulate(mf model.MediaFile) {
45: 	if mf.AlbumID != "" {
46: 		r.album[mf.AlbumID] = struct{}{}
47: 	}
48: 	if mf.AlbumArtistID != "" {
49: 		r.artist[mf.AlbumArtistID] = struct{}{}
50: 	}
51: }
52: 
53: func (r *refresher) flush(ctx context.Context) error {
54: 	err := r.flushMap(ctx, r.album, "album", r.refreshAlbums)
55: 	if err != nil {
56: 		return err
57: 	}
58: 	r.album = map[string]struct{}{}
59: 	err = r.flushMap(ctx, r.artist, "artist", r.refreshArtists)
60: 	if err != nil {
61: 		return err
62: 	}
63: 	r.artist = map[string]struct{}{}
64: 	return nil
65: }
66: 
67: type refreshCallbackFunc = func(ctx context.Context, ids ...string) error
68: 
69: func (r *refresher) flushMap(ctx context.Context, m map[string]struct{}, entity string, refresh refreshCallbackFunc) error {
70: 	if len(m) == 0 {
71: 		return nil
72: 	}
73: 
74: 	for chunk := range slice.CollectChunks(maps.Keys(m), 200) {
75: 		err := refresh(ctx, chunk...)
76: 		if err != nil {
77: 			log.Error(ctx, fmt.Sprintf("Error writing %ss to the DB", entity), err)
78: 			return err
79: 		}
80: 	}
