			// Create invalid/unsupported file
			invalidFile := filepath.Join(tempDir, "invalid.txt")
			err := os.WriteFile(invalidFile, []byte("This is not an audio file"), 0o644)
			Expect(err).NotTo(HaveOccurred())

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())

			// Verify only valid file was processed
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(1))

			// Verify it's the valid file
			Expect(allFiles[0].Path).To(Equal(validFile))
			Expect(allFiles[0].Title).To(ContainSubstring("Valid Song"))
		})
	})

	Describe("Track number and year extraction", func() {
		It("should correctly extract track numbers and years from metadata", func() {
			// Create audio files with different track numbers and years
			createTestAudioFile(tempDir, "track_01.mp3", "First Track", "Artist", "Album", 1, 2020)
			createTestAudioFile(tempDir, "track_05.mp3", "Fifth Track", "Artist", "Album", 5, 2021)
			createTestAudioFile(tempDir, "track_12.mp3", "Twelfth Track", "Artist", "Album", 12, 2022)

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

