			close(progress)

			Expect(err).NotTo(HaveOccurred())

			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(3))

			// Create map by title for easier verification
			filesByTitle := make(map[string]model.MediaFile)
			for _, mf := range allFiles {
				filesByTitle[mf.Title] = mf
			}

			Expect(filesByTitle["First Track"].TrackNumber).To(Equal(1))
