	tests.Init(t, true)
	log.SetLevel(log.LevelFatal)
	RegisterFailHandler(Fail)
	RunSpecs(t, "Scanner Integration Suite")
}

var _ = Describe("Scanner Integration Tests", func() {
	var (
		ctx        context.Context
		tempDir    string
		lib        model.Library
		mediaRepo  *tests.MockMediaFileRepo
		albumRepo  *tests.MockAlbumRepo
		artistRepo *tests.MockArtistRepo
		ds         *tests.MockDataStore
		mockBroker *MockEventBroker
	)

	BeforeEach(func() {
		ctx = context.Background()

		// Create a temporary directory for test fixtures
		var err error
		tempDir, err = os.MkdirTemp("", "navidrome-scan-test-*")
		Expect(err).NotTo(HaveOccurred())

		// Set up the test library
		lib = model.Library{
			ID:         1,
			Name:       "Test Library",
			Path:       tempDir,
			LastScanAt: time.Time{},
		}

		// Set up mock repositories
		mediaRepo = tests.CreateMockMediaFileRepo()
		albumRepo = tests.CreateMockAlbumRepo()
		artistRepo = tests.CreateMockArtistRepo()
		mockBroker = &MockEventBroker{}

		ds = &tests.MockDataStore{
			MockedMediaFile: mediaRepo,
			MockedAlbum:     albumRepo,
			MockedArtist:    artistRepo,
		}

		// Configure conf for scanner
		conf.Server.Scanner.Extractor = "taglib"
	})

	AfterEach(func() {
		if tempDir != "" {
			os.RemoveAll(tempDir)
		}
	})

	Describe("Full scan with audio files", func() {
		It("should scan and extract metadata from audio files", func() {
			// Create test audio files with metadata
			audioFile1 := createTestAudioFile(tempDir, "song1.mp3", "Test Song 1", "Test Artist", "Test Album", 1, 2023)
			audioFile2 := createTestAudioFile(tempDir, "song2.mp3", "Test Song 2", "Test Artist", "Test Album", 2, 2023)

			Expect(audioFile1).To(BeAnExistingFile())
			Expect(audioFile2).To(BeAnExistingFile())

			// Create scanner and scan
			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)), "should detect changes")

			// Verify mediafiles were stored
			allFiles, err := mediaRepo.GetAll()

			Expect(err).NotTo(HaveOccurred())
			Expect(len(allFiles)).To(BeLessThanOrEqualTo(fileCountAfterFirstScan))
		})
	})

	Describe("Album and artist record creation", func() {
		It("should create album and artist records from metadata", func() {
			// Create multiple songs by same artist in same album
			createTestAudioFile(tempDir, "track1.mp3", "Track 1", "The Beatles", "Abbey Road", 1, 1969)
			createTestAudioFile(tempDir, "track2.mp3", "Track 2", "The Beatles", "Abbey Road", 2, 1969)
			createTestAudioFile(tempDir, "track3.mp3", "Track 3", "The Beatles", "Abbey Road", 3, 1969)

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)))

			// Verify media files were created with proper album/artist IDs
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(3))

			// All files should have same AlbumID and ArtistID
			var albumID string
			var artistID string
			for _, mf := range allFiles {
				if albumID == "" {
					albumID = mf.AlbumID
					artistID = mf.ArtistID
				}
				Expect(mf.AlbumID).To(Equal(albumID), "all tracks should have same album ID")
				Expect(mf.ArtistID).To(Equal(artistID), "all tracks should have same artist ID")
				Expect(mf.Album).To(ContainSubstring("Abbey Road"))
				Expect(mf.Artist).To(ContainSubstring("The Beatles"))
			}
		})
	})

	Describe("Handling empty directories", func() {
		It("should not process empty directories", func() {
			// Create empty subdirectory
			subDir := filepath.Join(tempDir, "empty_subdir")
			err := os.Mkdir(subDir, 0o755)
			Expect(err).NotTo(HaveOccurred())

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(0)), "empty directory should not trigger changes")

			// Verify no media files were added
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(0))
		})
	})

	Describe("Handling mixed valid and invalid files", func() {
		It("should process valid audio files and skip invalid ones", func() {
			// Create valid audio file
			validFile := createTestAudioFile(tempDir, "valid.mp3", "Valid Song", "Artist", "Album", 1, 2023)

			// Create invalid/unsupported file
			invalidFile := filepath.Join(tempDir, "invalid.txt")
			err := os.WriteFile(invalidFile, []byte("This is not an audio file"), 0o644)
			Expect(err).NotTo(HaveOccurred())

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())

			// Verify only valid file was processed
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(1))

			// Verify it's the valid file
			Expect(allFiles[0].Path).To(Equal(validFile))
			Expect(allFiles[0].Title).To(ContainSubstring("Valid Song"))
		})
	})

	Describe("Track number and year extraction", func() {
		It("should correctly extract track numbers and years from metadata", func() {
			// Create audio files with different track numbers and years
			createTestAudioFile(tempDir, "track_01.mp3", "First Track", "Artist", "Album", 1, 2020)
			createTestAudioFile(tempDir, "track_05.mp3", "Fifth Track", "Artist", "Album", 5, 2021)
			createTestAudioFile(tempDir, "track_12.mp3", "Twelfth Track", "Artist", "Album", 12, 2022)

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			_, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())

			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(3))

			// Create map by title for easier verification
			filesByTitle := make(map[string]model.MediaFile)
			for _, mf := range allFiles {
				filesByTitle[mf.Title] = mf
			}

			Expect(filesByTitle["First Track"].TrackNumber).To(Equal(1))
			Expect(filesByTitle["First Track"].Year).To(Equal(2020))

			Expect(filesByTitle["Fifth Track"].TrackNumber).To(Equal(5))
			Expect(filesByTitle["Fifth Track"].Year).To(Equal(2021))

			Expect(filesByTitle["Twelfth Track"].TrackNumber).To(Equal(12))
			Expect(filesByTitle["Twelfth Track"].Year).To(Equal(2022))
		})
	})

	Describe("Library ID assignment", func() {
		It("should assign correct library ID to all scanned files", func() {
			lib.ID = 42
			createTestAudioFile(tempDir, "song1.mp3", "Title 1", "Artist", "Album", 1, 2023)
			createTestAudioFile(tempDir, "song2.mp3", "Title 2", "Artist", "Album", 2, 2023)

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			_, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())

			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// All files should have the correct library ID
			for _, mf := range allFiles {
				Expect(mf.LibraryID).To(Equal(42))
			}
		})
	})
})

// Helper function to create test audio files
// In a real scenario, these would be actual audio files with metadata.
// For this integration test, we create simple files that represent audio tracks.
func createTestAudioFile(dir, filename, title, artist, album string, trackNum, year int) string {
	filePath := filepath.Join(dir, filename)
	// Create a placeholder file - the actual metadata would be read by the metadata extractor
	content := fmt.Sprintf("TIT2:%s\nTPE1:%s\nTALB:%s\nTRCK:%d\nTDRC:%d\n",
		title, artist, album, trackNum, year)
	err := os.WriteFile(filePath, []byte(content), 0o644)
	if err != nil {
		panic(err)
	}
	return filePath
}

